1318 void SCCPInstVisitor::handleExtractOfWithOverflow(ExtractValueInst &EVI,
1319                                                   const WithOverflowInst *WO,
1320                                                   unsigned Idx) {
1321   Value *LHS = WO->getLHS(), *RHS = WO->getRHS();
1322   ValueLatticeElement L = getValueState(LHS);
1323   ValueLatticeElement R = getValueState(RHS);
1324   addAdditionalUser(LHS, &EVI);
1325   addAdditionalUser(RHS, &EVI);
1326   if (L.isUnknownOrUndef() || R.isUnknownOrUndef())
1327     return; // Wait to resolve.
1328 
1329   Type *Ty = LHS->getType();
1330   ConstantRange LR = getConstantRange(L, Ty);
1331   ConstantRange RR = getConstantRange(R, Ty);
1332   if (Idx == 0) {
1333     ConstantRange Res = LR.binaryOp(WO->getBinaryOp(), RR);
1334     mergeInValue(&EVI, ValueLatticeElement::getRange(Res));
1335   } else {
1336     assert(Idx == 1 && "Index can only be 0 or 1");
1337     ConstantRange NWRegion = ConstantRange::makeGuaranteedNoWrapRegion(
1338         WO->getBinaryOp(), RR, WO->getNoWrapKind());
1339     if (NWRegion.contains(LR))
1340       return (void)markConstant(&EVI, ConstantInt::getFalse(EVI.getType()));
1341     markOverdefined(&EVI);
1342   }
